logger = logging.getLogger()
logger.setLevel(logging.INFO)

s3 = boto3.client("s3")
sns = boto3.client("sns")

OUTPUT_BUCKET = os.environ.get("OUTPUT_BUCKET")
OUTPUT_PREFIX = os.environ.get("OUTPUT_PREFIX", "processed/")
SNS_TOPIC_ARN = os.environ.get("SNS_TOPIC_ARN")


def lambda_handler(event, context):
    logger.info("Received event: %s", json.dumps(event))

    results = []

    for record in event.get("Records", []):
        try:
            if record.get("eventSource") != "aws:s3":
                logger.warning("Skipping non-S3 event record: %s", record)
                continue

            source_bucket = record["s3"]["bucket"]["name"]
            source_key = unquote_plus(record["s3"]["object"]["key"])

            result = process_image(source_bucket, source_key)
            results.append(result)

            publish_notification(
                subject="Image Processing Succeeded",
                message={
                    "status": "success",
                    "source_bucket": source_bucket,
                    "source_key": source_key,
                    "output_bucket": result["output_bucket"],
                    "output_key": result["output_key"],
                },
            )

        except Exception as e:
            logger.error("Failed processing record: %s", str(e))
            logger.error(traceback.format_exc())

            failed_bucket = (
                record.get("s3", {}).get("bucket", {}).get("name")
                if isinstance(record, dict)
                else None
            )
            failed_key = (
                unquote_plus(record.get("s3", {}).get("object", {}).get("key", ""))
                if isinstance(record, dict) and record.get("s3", {}).get("object", {}).get("key")
                else None
            )

            publish_notification(
                subject="Image Processing Failed",
                message={
                    "status": "failure",
                    "source_bucket": failed_bucket,
                    "source_key": failed_key,
                    "error": str(e),
                },
            )

    return {
        "statusCode": 200,
        "body": json.dumps(
            {
                "message": "Processing complete",
                "results": results,
            }
        ),
    }


def process_image(bucket, key):
    logger.info("Reading object from S3: s3://%s/%s", bucket, key)
    response = s3.get_object(Bucket=bucket, Key=key)
    original_bytes = response["Body"].read()

    processed_bytes = transform_image_bytes(original_bytes, key)

    output_bucket = OUTPUT_BUCKET or bucket
    output_key = build_output_key(key)

    logger.info("Writing processed object to S3: s3://%s/%s", output_bucket, output_key)
    s3.put_object(
        Bucket=output_bucket,
        Key=output_key,
        Body=processed_bytes,
        ContentType=response.get("ContentType", "application/octet-stream"),
        Metadata={
            "source-bucket": bucket,
            "source-key": key,
            "processed-by": "aws-lambda",
        },
    )

    return {
        "source_bucket": bucket,
        "source_key": key,
        "output_bucket": output_bucket,
        "output_key": output_key,
        "size_in": len(original_bytes),
        "size_out": len(processed_bytes),
    }


def transform_image_bytes(data, key):
    logger.info("Applying placeholder image transformation for key: %s", key)
    return data


def build_output_key(source_key):
    filename = source_key.split("/")[-1]
    return f"{OUTPUT_PREFIX}{filename}"


def publish_notification(subject, message):
    if not SNS_TOPIC_ARN:
        logger.info("SNS_TOPIC_ARN not configured; skipping notification: %s", json.dumps(message))
        return

    try:
        sns.publish(
            TopicArn=SNS_TOPIC_ARN,
            Subject=subject,
            Message=json.dumps(message),
        )
        logger.info("Published SNS notification: %s", subject)
    except ClientError as e:
        logger.error("Failed to publish SNS notification: %s", str(e))